var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>익명의 태스크포스 컴퍼니로부터 수신한 메일입니다.</color>`,JPN:`<color=#ffd34c>匿名のタスクフォースカンパニーから受信したメールです。</color>`,ENG:`<color=#ffd34c>A mail arrived from an anonymous TASKFORCE Company.</color>`,TWN:`<color=#ffd34c>來自匿名特遣勢力公司的郵件。</color>`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`이터니움 확보를 위해 다이브를 진행했던 파견순양함으로부터 기함 파손 신고를 접수 받았습니다.`,JPN:`エタニウム確保のためにダイブした派遣巡洋艦から、艦船の破損申告がありました。`,ENG:`We received a report that our cruiser that was deployed in a dive damaged our flagship while acquiring Eternium.`,TWN:`我們接收到了一份來自為了獲取永恆之金正在進行躍入的派遣巡洋艦的損毀報告。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`수복이 불가능할 정도의 손상은 아니지만, 문제는 포인트에 있는 다수의 변종 침식체들입니다.`,JPN:`修復が不可能な損傷ではありませんが、問題は多数の変種侵食体がポイントにいることです。`,ENG:`Although the damage can be recovered, there are multiple mutated C.O.'s around the point that are causing a problem.`,TWN:`雖然不是無法修復的損傷程度，但問題是現場存在許多變種侵蝕體。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`엔지니어팀이 기함 수리를 무사히 마칠 수 있도록 호위를 요청합니다.`,JPN:`エンジニアチームが艦船の修理を無事に終えられるよう、護衛を要請します。`,ENG:`We are requesting your company to escort our engineer team until they are able to successfully repair our flagship.`,TWN:`希望你能保護工程隊的安全直到艦船修理完畢。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`차원간 통신이 신호가 마지막으로 확인된 좌표 정보를 함께 전달하겠습니다.`,JPN:`次元間通信の信号が最後に確認された座標の情報も一緒にお送りします。`,ENG:`The last confirmed coordinates based on the interdimensional communications are attached to this mail.`,TWN:`次元間的通信信號會把最終確認的座標情報一同傳送過去。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};